mapper.select:
SELECT gs.*, pgs.platform_id as platform_id, pgs.catalog_id as catalog_id FROM wvp_gb_stream gs
    LEFT JOIN wvp_platform_gb_stream pgs ON gs.gb_stream_id = pgs.gb_stream_id
WHERE gs.gb_id = #{gbId} AND pgs.platform_id = #{platformId}

SELECT gs.* FROM wvp_gb_stream gs
AND gs.gb_stream_id in (select pgs.gb_stream_id from wvp_platform_gb_stream pgs where pgs.platform_id = #{platformId} and pgs.catalog_id=#{catalogId}) AND gs.gb_stream_id not in (select pgs.gb_stream_id from wvp_platform_gb_stream pgs where pgs.platform_id = #{platformId}) AND (gs.app LIKE concat('%',#{query},'%') OR gs.stream LIKE concat('%',#{query},'%') OR gs.gb_id LIKE concat('%',#{query},'%') OR gs.name LIKE concat('%',#{query},'%')) AND gs.media_server_id=#{mediaServerId}
order by gs.gb_stream_id asc

SELECT gs.* FROM wvp_gb_stream gs
AND gs.gb_stream_id in (select pgs.gb_stream_id from wvp_platform_gb_stream pgs where pgs.platform_id = #{dto.platformId} and pgs.catalog_id=#{dto.catalogId}) AND gs.gb_stream_id not in (select pgs.gb_stream_id from wvp_platform_gb_stream pgs where pgs.platform_id = #{dto.platformId}) AND (gs.app LIKE concat('%',#{dto.query},'%') OR gs.stream LIKE concat('%',#{dto.query},'%') OR gs.gb_id LIKE concat('%',#{dto.query},'%') OR gs.name LIKE concat('%',#{dto.query},'%')) AND gs.media_server_id=#{dto.mediaServerId}
order by gs.gb_stream_id asc
